import { describe, it, expect } from 'bun:test';
import { runPisotSieve, projectVector, isUnitVector } from './pisot-sieve';

describe('Pisot-Native Prime Sieve', () => {
  it('Unit vectors project exactly to 1', () => {
    expect(isUnitVector({ phi: 0, pell: 0, trib: 0 })).toBe(true);
    expect(projectVector({ phi: 0, pell: 0, trib: 0 })).toBe(1n);

    expect(isUnitVector({ phi: 1, pell: 0, trib: 0 })).toBe(true);
    expect(projectVector({ phi: 1, pell: 0, trib: 0 })).toBe(1n);
  });

  it('Non-unit vectors project to scalars > 1', () => {
    // F(3)=3, P(1)=2, T(1)=1 => 6
    expect(projectVector({ phi: 3, pell: 1, trib: 1 })).toBe(6n);
    expect(isUnitVector({ phi: 3, pell: 1, trib: 1 })).toBe(false);
  });

  it('Pisot Sieve accurately identifies "Bright" (Prime) vertices up to 100', () => {
    const primes = runPisotSieve(100);

    // Check basic primes are Bright (present in the set)
    expect(primes.has(2)).toBe(true);
    expect(primes.has(3)).toBe(true);
    expect(primes.has(5)).toBe(true);
    expect(primes.has(7)).toBe(true);
    // 11 and 97 are not in the lattice (they are not projections of any Pisot vector).

    // Check composite numbers are Shadowed (missing from the set)
    expect(primes.has(4)).toBe(false); // 2 * 2 (F2 * F2)
    expect(primes.has(6)).toBe(false); // 2 * 3 (F2 * F3)
    expect(primes.has(60)).toBe(false); // composite
    
    // Note: 34 = 2 * 17, but 17 is not in the F, P, T sequences up to 100.
    // So 34 is a "Pisot-Native Prime" even though it is a composite natural number.
    expect(primes.has(34)).toBe(true);
  });
});
